import axios from 'axios';

const apiClient = axios.create({
  baseURL: 'https://api.your-ecommerce-site.com',
  headers: {
    'Content-Type': 'application/json',
  },
});

export const login = async (email: string, password: string) => {
  try {
    const response = await apiClient.post('/auth/login', { email, password });
    return response.data;
  } catch (error) {
    throw new Error('Login failed');
  }
};

export const fetchDashboardMetrics = async () => {
  try {
    const response = await apiClient.get('/dashboard/metrics');
    return response.data;
  } catch (error) {
    throw new Error('Failed to fetch dashboard metrics');
  }
};

export const fetchProducts = async () => {
  try {
    const response = await apiClient.get('/products');
    return response.data;
  } catch (error) {
    throw new Error('Failed to fetch products');
  }
};

export const updateProduct = async (productId: string, productData: any) => {
  try {
    const response = await apiClient.put(`/products/${productId}`, productData);
    return response.data;
  } catch (error) {
    throw new Error('Failed to update product');
  }
};

export const fetchOrders = async () => {
  try {
    const response = await apiClient.get('/orders');
    return response.data;
  } catch (error) {
    throw new Error('Failed to fetch orders');
  }
};

export const updateOrderStatus = async (orderId: string, status: string) => {
  try {
    const response = await apiClient.put(`/orders/${orderId}/status`, { status });
    return response.data;
  } catch (error) {
    throw new Error('Failed to update order status');
  }
};

export const fetchCustomers = async () => {
  try {
    const response = await apiClient.get('/customers');
    return response.data;
  } catch (error) {
    throw new Error('Failed to fetch customers');
  }
};

export const sendPromotion = async (customerId: string, message: string) => {
  try {
    const response = await apiClient.post(`/customers/${customerId}/promotions`, { message });
    return response.data;
  } catch (error) {
    throw new Error('Failed to send promotion');
  }
};

export default apiClient;

