export const formatCurrency = (amount: number) => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
  }).format(amount);
};

export const formatDate = (dateString: string) => {
  const options: Intl.DateTimeFormatOptions = {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  };
  return new Date(dateString).toLocaleDateString(undefined, options);
};

export const calculateTotalSales = (orders: any[]) => {
  return orders.reduce((total, order) => total + order.totalAmount, 0);
};

export const filterOrdersByStatus = (orders: any[], status: string) => {
  return orders.filter(order => order.status === status);
};

export const getLowStockItems = (products: any[], threshold: number) => {
  return products.filter(product => product.stock <= threshold);
};

export const generateCSV = (data: any[], headers: string[]) => {
  const csvRows = [headers.join(',')];
  data.forEach(item => {
    const values = headers.map(header => item[header]);
    csvRows.push(values.join(','));
  });
  return csvRows.join('\n');
};
